import os
import json
from google.cloud import storage

class ModelLoader(object):
    def __init__(self, model_path=None):
        self.model_path = model_path or os.environ['MODEL_PATH']
        self.client = storage.Client()
    
    def load_latest_version(self):
        bucket_name = self.model_path.split('/')[2]
        object_name = '/'.join(self.model_path.split('/')[3:])
        bucket = self.client.get_bucket(bucket_name)
        blob = bucket.blob(object_name)
        model = blob.download_as_string()
        return json.loads(model)
    
    def load_model(self, version=None):
        if version is None:
            version = self.load_latest_version()
        bucket_name = self.model_path.split('/')[2]
        object_name = f'{self.model_path}/{version}'
        bucket = self.client.get_bucket(bucket_name)
        blob = bucket.blob(object_name)
        model = blob.download_as_string()
        return json.loads(model)